INSERT INTO public.photos VALUES (21595, 'Calle Don Jaime c.1920', 'Calle de Don Jaime I, en su confluencia con la del Pilar (al fondo a la izquierda). Tras el caballero de primer plano, la Lonja. A la izquierda, comercio de recuerdos neoclasicista. Fuente: Foto Jesâ”œâ•‘s Cormâ”œÃ­n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65559800, -0.87660000, '0101000020E6100000228E75711B0DECBF58A9A0A2EAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24878756026.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24878756026.webp', 'https://www.flickr.com/photos/zaragozaantigua/24878756026/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21649, 'Calle del Pilar 1923', 'Inâ”œÂ®dita imagen capturada en la calle del Pilar, esquina con la plaza de la Seo y la calle de Fernando el Catâ”œâ”‚lico, que hacia el fondo y a la derecha conduce al paseo del Ebro y el puente de Piedra. En primer tâ”œÂ®rmino, una vendedora ambulante de frutas y verduras, entre las que destacan granadas de temporada. Frente a ella, el "brasero" o solanera de la Lonja, donde se arrima hasta una pareja de urbanos junto a otro puesto ambulante.', 1923, 1923, 1923, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65555100, -0.87670600, '0101000020E61000008C9FC6BDF90DECBF18EE5C18E9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51371172171.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51371172171.webp', 'https://www.flickr.com/photos/zaragozaantigua/51371172171/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21659, 'Plaza de La Seo, c.1920', 'Imagen tomada en la plaza de La Seo, donde destaca su isleta de verdor centrada en la Fuente de la Samaritana y la ingrata presencia de su denostado mingitorio. Hacia el fondo y tras la calle de Fernando el Catâ”œâ”‚lico, ensanche de la calle del Pilar.', 1920, 1920, 1920, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65547900, -0.87635200, '0101000020E61000001A187959130BECBF7E1B62BCE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53605982143.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53605982143.webp', 'https://www.flickr.com/photos/zaragozaantigua/53605982143/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21740, 'Lonja 1933', 'Imagen de conjunto de la antigua Lonja y Casa de la Moneda de la ciudad, capturada en cierta altura desde el Seminario Diocesano. En primer plano, las traseras del edificio convertidas en despejada zona de jardines y disfrute ciudadano, tras derribo de las antiguas Casas de la Ciudad. A la izquierda, la calle Fernando el Catâ”œâ”‚lico que conduce a la plaza de la Seo. A la derecha, la que fuera Posada del Rey, junto al palacio de los marqueses de Ayerbe, y el Pilar. Fuente visual: "Revista Espaâ”œâ–’ola de Turismo".', 1933, 1933, 1933, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65588600, -0.87624900, '0101000020E6100000F3E2C4573B0AECBFBFF38B12F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21776602559.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21776602559.webp', 'https://www.flickr.com/photos/zaragozaantigua/21776602559/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
