INSERT INTO public.photos VALUES (21767, 'Jardines de La Lonja 1932', 'Jardines de la Lonja junto al paseo de la Ribera. Al fondo, el palacio de los marqueses de Ayerbe y el Pilar. Fuente visual: Foto Conrado Barlâ”œÂ®s, donada por Daniel Barlâ”œÂ®s y digitalizada por Josâ”œÂ® Luis Cintora para www.rafaelcastillejo.com', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65610300, -0.87648200, '0101000020E6100000A60BB1FA230CECBF5CE7DF2EFBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22622365053.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22622365053.webp', 'https://www.flickr.com/photos/zaragozaantigua/22622365053/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21884, 'La Lonja 1938', 'Imagen capturada en los jardines traseros de la Lonja, donde los posados con palomas se habâ”œÂ¡an convertido en una antropolâ”œâ”‚gica tradiciâ”œâ”‚n. En este caso, el objetivo se centra, entre bancas palomas, en uno de los aviadores alemanes de la Legiâ”œâ”‚n Câ”œâ”‚ndor radicados en la ciudad y con servicio en el grupo de bombardeo K/88 establecido en el aerâ”œâ”‚dromo Sanjurjo. Por el paseo del Ebro, al fondo, coincide concurrido trâ”œÃ­fico de caballerâ”œÂ¡a, carro, y vehâ”œÂ¡culo a motor. A la derecha, quiosco de los jardines.', 1938, 1938, 1938, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65640500, -0.87693400, '0101000020E6100000CD0358E4D70FECBF27F73B1405D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49596274877.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49596274877.webp', 'https://www.flickr.com/photos/zaragozaantigua/49596274877/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21897, 'Calle del Pilar c.1934', 'Imagen capturada en la calle del Pilar con el objetivo dirigido hacia la plaza de La Seo, donde destaca a la izquierda el arco del Arzobispo. Unos guardias de asalto caminan junto a la Lonja en direcciâ”œâ”‚n a la plaza del Pilar. A la derecha, el singular establecimiento "El Pilar", multitienda de objetos artâ”œÂ¡sticos de recuerdo, objetos de escritorio y ornamentos religiosos.', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65572700, -0.87686700, '0101000020E6100000D921FE614B0FECBF560DC2DCEED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50945685863.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50945685863.webp', 'https://www.flickr.com/photos/zaragozaantigua/50945685863/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21925, 'Ribera del Pilar c.1940', 'AHPZ-Archivo Fotogrâ”œÃ­fico Josâ”œÂ® Galiay, (SF). El Pilar desde la ribera del Ebro.', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65629600, -0.87643300, '0101000020E61000004C530438BD0BECBF703FE08101D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14700887978.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14700887978.webp', 'https://www.flickr.com/photos/zaragozaantigua/14700887978/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22202, 'Ximâ”œÂ®nez de Embâ”œâ•‘n 1958', 'Imagen de la calle de Tomâ”œÃ­s Ximâ”œÂ®nez de Embâ”œâ•‘n capturada desde la ampliada plaza del Pilar. A la izquierda, el edificio en construcciâ”œâ”‚n de la nueva Casa Consistorial. A la derecha, la Lonja. Al fondo, el paseo del Ebro, y el fondo escâ”œÂ®nico de la margen izquierda. Fuente visual: archivo Heraldo de Aragâ”œâ”‚n, en "Padre Ebro. El râ”œÂ¡o Ebro y el siglo XX".', 1958, 1958, 1958, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65590600, -0.87700600, '0101000020E610000032AA0CE36E10ECBF06A051BAF4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33823491101.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33823491101.webp', 'https://www.flickr.com/photos/zaragozaantigua/33823491101/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22219, 'Plaza del Pilar 1954', 'Imagen capturada desde la torre de la Seo, posiblemente a la altura de su segundo cuerpo en ladrillo, con una buena perspectiva de la nueva plaza de las Catedrales como sumatorio de las antiguas plazas del Pilar y de Huesca, para convertirse en escenario de multitudinarias ceremonias de reafirmaciâ”œâ”‚n del râ”œÂ®gimen franquista y su â”œÂ¡ntima vinculaciâ”œâ”‚n con la iglesia catâ”œâ”‚lica. En primer tâ”œÂ®rmino, breve visual de la arbolada plaza de La Seo y de la calle de Don Jaime I. A la derecha, Lonja y andamios de obra de la nueva Casa Consistorial, cuyo avanzado desarrollo en la fachada recayente a la plaza se debâ”œÂ¡a al Congreso Mariano de este aâ”œâ–’o, para dar una imagen escâ”œÂ®nica de falso acabado ante los miles de congresistas venidos de fuera de la ciudad. Del templo del Pilar, detrâ”œÃ­s, despuntan las obras de las dos nuevas torres ribereâ”œâ–’as, patrocinadas econâ”œâ”‚micamente por Francisco Urzaiz y Leonor Sala, cuando ambas todavâ”œÂ¡a ascendâ”œÂ¡an en sintonâ”œÂ¡a, luego rota por el mayor desarrollo de la torre noroeste en su finalizaciâ”œâ”‚n.', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65552700, -0.87688900, '0101000020E6100000CE1B2785790FECBF8F52094FE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48300029697.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48300029697.webp', 'https://www.flickr.com/photos/zaragozaantigua/48300029697/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22236, 'Plaza del Pilar 1954', 'Imagen capturada desde la altura del inmueble chaflanero entre la plaza de La Seo y la calle de Don Jaime I, con una vista centrada en la plaza del Pilar. Por la derecha y sobre el firme se destaca la alargada sombra de la torre de la Seo. Tras ella, la Lonja y la nueva Casa Consistorial haciendo las funciones de una "aldea Potemkim": la fachada recayente a la plaza ha sido terminada a marchas forzadas para el Congreso Mariano celebrado en este entorno, mientras el resto seguâ”œÂ¡a en obras. A su lado, el templo del Pilar con las torres de la ribera en construcciâ”œâ”‚n. Al fondo, resplandece al sol el reciâ”œÂ®n terminado "Altar de la Patria" o "Monumento a los hâ”œÂ®roes y mâ”œÃ­rtires de Zaragoza. Caâ”œÂ¡dos en la Cruzada de Liberaciâ”œâ”‚n 1936-1939".', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65567900, -0.87673900, '0101000020E61000007B1684F23E0EECBF45D61A4AEDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50682145953.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50682145953.webp', 'https://www.flickr.com/photos/zaragozaantigua/50682145953/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22267, 'Cine Pax 1968', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/diciembre 1968. Los 60 arrancaban en la ciudad con la apertura de varios Cines (no "salas" de cine, Cines), porque en Espaâ”œâ–’a la televisiâ”œâ”‚n aâ”œâ•‘n no amenazaba con matar a la estrella de la radio, y del cine. Asâ”œÂ¡, en 1961 abrieron sus puertas el "Dux" y el "Roxy", dos cines "de barrio", en San Josâ”œÂ® y Montemolâ”œÂ¡n, respectivamente. En 1963 vio la luz el "Pax", en la Plaza de la Seo nâ”¬â•‘ 6, con capacidad de 600 personas, y orientado hacia un tipo de cine entre lo familiar, y lo tolerado-para-todos-los-pâ”œâ•‘blicos. Serâ”œÃ­ clausurado en 1984, junto con otros 15 cines de la ciudad (entre ellos, todos los cines de barrio). En la imagen, animada fila para el "Pax" cuando proyectaba el norteamericano filme "Rosie!", al que la peculiar espaâ”œâ–’olizaciâ”œâ”‚n del tâ”œÂ¡tulo le habâ”œÂ¡a aâ”œâ–’adido la coletilla "Una seâ”œâ–’ora riquâ”œÂ¡sima", una comedia donde aparecâ”œÂ¡a la angelical Sandra Dee, la misma que una dâ”œÂ®cada despuâ”œÂ®s serâ”œÂ¡a parodiada con caâ”œâ•‘stica gracia en "Grease".', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65551900, -0.87617000, '0101000020E6100000EF8FF7AA9509ECBF0C74ED0BE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14850753965.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14850753965.webp', 'https://www.flickr.com/photos/zaragozaantigua/14850753965/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22285, 'Riada de 1961', 'Foto Heraldo de Aragâ”œâ”‚n, 1961. La riada del Ebro a su paso por el puente de Piedra de Zaragoza en enero de 1961, la mayor del siglo XX. Fuente: www.heraldo.es/noticias/especiales/2014/07/11/grandes_ria...', 1961, 1961, 1961, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65625900, -0.87638600, '0101000020E61000001F8315A75A0BECBF535A7F4B00D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15161139382.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15161139382.webp', 'https://www.flickr.com/photos/zaragozaantigua/15161139382/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22647, 'La Lonja 1970', 'Celebraciâ”œâ”‚n del concurso Maja Internacional en el palacio de la Lonja de Zaragoza, el 11 de mayo de 1970. Este certamen tuvo su sede en la ciudad en diez ocasiones, entre 1966 y 1975. En 1970 resultâ”œâ”‚ ganadora la representante de Chile, Marâ”œÂ¡a Isabel Pâ”œÂ®rez (quinta por la izquierda). Fuente: www.chileancharm.com/', 1970, 1970, 1970, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65572700, -0.87652800, '0101000020E6100000BCE7C072840CECBF560DC2DCEED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20928761109.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20928761109.webp', 'https://www.flickr.com/photos/zaragozaantigua/20928761109/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23173, 'Antonio Lâ”œâ”‚pez 2009', 'Imagen del pintor manchego Antonio Lâ”œâ”‚pez Garcâ”œÂ¡a en la plaza del Pilar, durante una apariciâ”œâ”‚n pâ”œâ•‘blica en la que se ofreciâ”œâ”‚ al Cabildo del Pilar para pintar una bâ”œâ”‚veda del templo, y esculpir un bulto redondo relacionado. A la izquierda del pintor, el cenotafio de Goya que antes estuviera en el Rincâ”œâ”‚n de Goya del Parque de Buenavista. Tras retrasos y contingencias varias, el 11 de enero de 2016, pocos dâ”œÂ¡as despuâ”œÂ®s del cumpleaâ”œâ–’os 80 de este pintor, fue presentado, mediante una proyecciâ”œâ”‚n sobre la câ”œâ•‘pula objeto de la intervenciâ”œâ”‚n, el boceto con la imagen del rostro de una mujer que simbolizaba a la Virgen Marâ”œÂ¡a. El carâ”œÃ­cter hiperrealista de la pintura propuesta, en lâ”œÂ¡nea con el reconocido estilo del autor, y la ausencia de los tradicionales sâ”œÂ¡mbolos y atributos marianos, llevaron al Cabildo a descartar el proyecto por no adecuado, o lejano de la oficial iconodulâ”œÂ¡a mariana. Fuente visual: foto Josâ”œÂ® Miguel Marco, en www.tribunadelamoraleja.com/', 2009, 2009, 2009, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65562800, -0.87691200, '0101000020E6100000D9092FC1A90FECBFC32B499EEBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33274996414.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33274996414.webp', 'https://www.flickr.com/photos/zaragozaantigua/33274996414/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23797, 'Vista aâ”œÂ®rea 1990', 'Se aprecian las obras en la plaza del Pilar, el templete levantado frente a la Delegaciâ”œâ”‚n del Gobierno, los andamios de la restauraciâ”œâ”‚n de la Lonja, las ruinas del Foro romano en la plaza de La Seo, el Monumento a los Caâ”œÂ¡dos sin terminar de desmantelar...', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65571800, -0.87649800, '0101000020E6100000124DA088450CECBF03B34291EED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14885512645.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14885512645.webp', 'https://www.flickr.com/photos/zaragozaantigua/14885512645/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23805, 'Traseras Lonja 1927', 'Imagen desde cierta altura de las traseras de La Lonja, cuando presentaban una feraz zona verde, con visual de las traseras de los edificios de la calle del Pilar, y el Pilar, al fondo. En el jardâ”œÂ¡n del palacio del Marquâ”œÂ®s de Ayerbe, imagen del quiosco realizado con materiales reciclados del derribado palacio o casa de Torrellas (s. XV). Fuente: Instituto Amatller de Arte Hispâ”œÃ­nico (Arxiu Mas).', 1927, 1927, 1927, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65603200, -0.87641600, '0101000020E6100000C91D3691990BECBF939048DBF8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15284977933.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15284977933.webp', 'https://www.flickr.com/photos/zaragozaantigua/15284977933/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
