INSERT INTO public.photos VALUES (23862, 'Plaza del Pilar 1966', 'Totâ”œÂ®mica puesta en escena del acto de fe de "ver la tele", en aparatos de 20/24 pulgadas, en la plaza del Pilar, de noche, y en invierno. En el interior de la inmediata Lonja, a la derecha, estaba teniendo lugar una representaciâ”œâ”‚n de jotas, y los aparatos televisores retransmitâ”œÂ¡an a quienes no habâ”œÂ¡an podido entrar a verlo en directo, cortesâ”œÂ¡a de una local empresa especializada en la venta de electrodomâ”œÂ®sticos. En la imagen, las traseras del monumento a Francisco de Goya, como telâ”œâ”‚n de fondo al espectâ”œÃ­culo, de cuando "ver la tele" era un privilegiado entretenimiento. Fuente: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65554200, -0.87691100, '0101000020E6100000C21550A8A70FECBFC493DDCCE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30074102022.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30074102022.webp', 'https://www.flickr.com/photos/zaragozaantigua/30074102022/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
