INSERT INTO public.photos VALUES (23873, 'Procesiâ”œâ”‚n Lonja 1940', 'La Virgen del Pilar es llevada en procesiâ”œâ”‚n ante la Lonja, durante los actos del XIX centenario de su viaje a Zaragoza, exactamente el aâ”œâ–’o 40. Destaca la presencia de representantes civiles. Al fondo, la manzana de casas que en pocos aâ”œâ–’os serâ”œÃ­ derribada para construir el nuevo ayuntamiento. Fuente: www.facebook.com/groups/fotosantiguasdezaragoza/permalink...', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65562800, -0.87691200, '0101000020E6100000D9092FC1A90FECBFC32B499EEBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30880033041.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30880033041.webp', 'https://www.flickr.com/photos/zaragozaantigua/30880033041/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23876, 'Paseo del Ebro 1940', 'Imagen capturada en los jardines y zona de esparcimiento entre la antigua Lonja y el paseo del Ebro. A la izquierda, las traseras de los edificios recayentes a la calle del Pilar, como la antigua posada de los Reyes, y el palacio de Ayerbe, con su reciclado cenador que al fondo despunta del jardâ”œÂ¡n vallado. Fuente visual: Ferrâ”œÃ­n Forns Navarro, Ajuntament de Girona.', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65610300, -0.87648200, '0101000020E6100000A60BB1FA230CECBF5CE7DF2EFBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30979688124.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30979688124.webp', 'https://www.flickr.com/photos/zaragozaantigua/30979688124/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23883, 'Palacio de Ayerbe aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste que muestra la Posada de los Reyes y el Palacio de Ayerbe, en el paseo de la Ribera. Estos edificios se encontraban entre la Lonja y el Pilar. Fuente: Lâ”œÃ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65640500, -0.87693400, '0101000020E6100000CD0358E4D70FECBF27F73B1405D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31629399793.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31629399793.webp', 'https://www.flickr.com/photos/zaragozaantigua/31629399793/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23902, 'Plaza del Pilar 1967', 'Imagen capturada desde la altura del inmueble del nâ”¬â•‘ 1 de la plaza de La Seo, esquinero con la calle de Don Jaime I. con una vista de la plaza del Pilar que alcanza hasta San Juan de los Panetes, al fondo. En primer tâ”œÂ®rmino, el moderno Monumento a Goya. La ocupaciâ”œâ”‚n de la plaza como espacio de aparcamiento de vehâ”œÂ¡culos progresa adecuadamente.', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65548700, -0.87681400, '0101000020E61000002499D53BDC0EECBF01FA7DFFE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49328681616.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49328681616.webp', 'https://www.flickr.com/photos/zaragozaantigua/49328681616/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23904, 'Paseo del Ebro c.1930', 'Imagen capturada desde la altura del Seminario Conciliar en el arranque de la calle de Don Jaime I y orientada hacia el noroeste, siguiendo la perspectiva del paseo del Ebro. En primer tâ”œÂ®rmino, caseta del peso pâ”œâ•‘blico de la Puerta del â”œÃ¼ngel y los Jardines de la Lonja, las traseras de los inmuebles del tramo de los impares de la calle del Pilar, con el homâ”œâ”‚nimo templo de telâ”œâ”‚n de fondo edilicio. A la derecha, cauce del râ”œÂ¡o Ebro y arboleda de Macanaz,', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65612000, -0.87648100, '0101000020E61000008F17D2E1210CECBF32207BBDFBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50150605706.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50150605706.webp', 'https://www.flickr.com/photos/zaragozaantigua/50150605706/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23908, 'Paseo del Ebro c.1908', 'Despejada y luminosa imagen capturada en el paseo del Ebro a la altura del fielato de consumos de la Puerta del â”œÃ¼ngel, con una interesante panorâ”œÃ­mica de la antigua fachada urbana del inmediato tramo ribereâ”œâ–’o, desde la posada de los Reyes, junto a cuya solanera se concentran varios carros y caballerâ”œÂ¡as, las traseras y jardines de la gran casa de los Ayerbe, las casas de los Infantes y el templo del Pilar. A la derecha, poste del tendido elâ”œÂ®ctrico de la lâ”œÂ¡nea de Circunvalaciâ”œâ”‚n.', 1908, 1908, 1908, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65641700, -0.87668500, '0101000020E6100000AF997CB3CD0DECBFEBC4E57805D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51719140471.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51719140471.webp', 'https://www.flickr.com/photos/zaragozaantigua/51719140471/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23909, 'Plaza del Pilar 1966', 'Nocturna e invernal imagen capturada en la plaza del Pilar y en el entorno al monumento a Francisco de Goya, centrada en el montaje realizado por el establecimiento "Radio La Corona" consistente en la instalaciâ”œâ”‚n de algo mâ”œÃ­s de treinta televisores "Vanguard" para ofrecer la retransmisiâ”œâ”‚n de la ceremonia de homenaje al equipo cultural-deportivo que presidido por el fotâ”œâ”‚grafo Guillermo Fatâ”œÃ­s Ojuel representaba a Zaragoza en el concurso de TVE "La uniâ”œâ”‚n hace la fuerza" y en el que resultâ”œâ”‚ ganador. Tambiâ”œÂ®n fueron homenajeados los componentes del equipo finalista, de La Coruâ”œâ–’a. Ademâ”œÃ­s los ganadores se llevaron 999.999 pesetas, y 333.333 los finalistas. Mientras en la Lonja tenâ”œÂ¡a lugar la gran ceremonia de homenaje con presencia de las autoridades locales y del jefe de programas de TVE, seâ”œâ–’or Adolfo Suâ”œÃ­rez Gonzâ”œÃ­lez, siendo presentada y animada por los conductores del programa televisivo seâ”œâ–’ores Mario Beut y Antolâ”œÂ¡n Garcâ”œÂ¡a, estos televisores sirvieron al doble propâ”œâ”‚sito de ofrecer las imâ”œÃ­genes retransmitidas en directo a quienes no pudieron ingresar al interior de la Lonja, y de servir de publicidad para la firma comercial que los instalâ”œâ”‚. Al fondo y a la izquierda del abarrotado entorno al monumento a Goya, cartel luminoso del Cine Pax en la plaza de La Seo.', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65548700, -0.87681400, '0101000020E61000002499D53BDC0EECBF01FA7DFFE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52464858820.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52464858820.webp', 'https://www.flickr.com/photos/zaragozaantigua/52464858820/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23965, 'Requetâ”œÂ® navarro 1936', 'AHPZ. Archivo Coyne. Manuel Coyne. 1936. Tras el 18 de julio, voluntarios carlistas navarros, o requetâ”œÂ®s (denominaciâ”œâ”‚n de los soldados carlistas durante la Primera Guerra Carlista, 1833-1840), secundaron las fuerzas nacionalistas que se levantaron en armas contra la Repâ”œâ•‘blica democrâ”œÃ­tica. "Pacificada" Navarra, se plantaron como fuerza de choque armada en los frentes abiertos, como Zaragoza. En la imagen, el Ã”Ã‡Â£Tercio de Doâ”œâ–’a Marâ”œÂ¡a de las NievesÃ”Ã‡Ã˜ de requetâ”œÂ®s navarros, tras cruzar el puente de Piedra, llega al entorno de la Seo. A la izquierda, la Lonja y la calle del Pilar. Al fondo, el cuartel de San Lâ”œÃ­zaro.', 1936, 1936, 1936, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65571100, -0.87630900, '0101000020E61000004818062CB90AECBF50508A56EED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15020622255.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15020622255.webp', 'https://www.flickr.com/photos/zaragozaantigua/15020622255/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23971, 'Majas Internacionales 1975', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 27/05/1975. "Majas Internacionales." En coherencia con la declaraciâ”œâ”‚n por parte de la ONU de 1975 como "Aâ”œâ–’o Internacional de la Mujer", en Zaragoza se celebra la orgâ”œÃ­nica elecciâ”œâ”‚n de la "Maja Internacional". En la imagen, las aspirantes al tâ”œÂ¡tulo, tras una recepciâ”œâ”‚n oficial en el Ayuntamiento a cargo del Alcalde, Mariano Horno Liria, hacen un simpâ”œÃ­tico posado-homenaje ante el monumento a Francisco Goya en la Plaza del Pilar, pero Goya no cabe en la foto. Al fondo, a la izquierda, cartel del Cine Pax. A la derecha, encima de la Estatua de la Libertad humanizada, visual de la plaza de La Seo.', 1975, 1975, 1975, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65548700, -0.87679200, '0101000020E6100000309FAC18AE0EECBF01FA7DFFE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15111823609.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15111823609.webp', 'https://www.flickr.com/photos/zaragozaantigua/15111823609/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23979, 'Muâ”œâ–’ecos timbaleros 1905', 'Fotograbado "La Luz". 1905. "Los timbaleros del Ayuntamiento". Esta tarjeta postal reproduce el fotomontaje de unos muâ”œâ–’ecos vestidos con el uniforme de Timbaleros del Ayuntamiento, delante de una imagen de la fachada del entonces edificio del Ayuntamiento de la ciudad, situado en las traseras de La Lonja. Aâ”œâ–’os despuâ”œÂ®s el Ayuntamiento serâ”œÂ¡a trasladado a la calle de la Democracia. Fuente: "La tarjeta postal ilustrada", Francisco Palâ”œÃ­ Laguna.', 1905, 1905, 1905, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65603200, -0.87641600, '0101000020E6100000C91D3691990BECBF939048DBF8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15299563115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15299563115.webp', 'https://www.flickr.com/photos/zaragozaantigua/15299563115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23980, 'Pablo Serrano 1975', 'Pablo Serrano Aguilar durante el montaje de la Exposiciâ”œâ”‚n antolâ”œâ”‚gica organizada por la Comisiâ”œâ”‚n de Cultura del Ayuntamiento en el Palacio de la Lonja (marzo-abril de 1975), con el posado del autor junto a Interpretaciâ”œâ”‚n de La Piedad, una de las obras expuestas. En septiembre de ese aâ”œâ–’o, y en protesta por los fusilamientos ejecutados por el râ”œÂ®gimen franquista a finales de ese mes, retirâ”œâ”‚ su obra de la exposiciâ”œâ”‚n Telecom 75 (Ginebra, Suiza).', 1975, 1975, 1975, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65584700, -0.87662100, '0101000020E6100000FF93BF7B470DECBF011764CBF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15302777212.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15302777212.webp', 'https://www.flickr.com/photos/zaragozaantigua/15302777212/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24071, 'La Lonja 1966', 'Imagen de la danesa Jeannette Christjansen (centro) tras su proclamaciâ”œâ”‚n como Maja Internacional 1966 en la Lonja, acompaâ”œâ–’ada de sus cuatro Damas de Honor: de izquierda a derecha, la irlandesa Muriel O''Hanlon, la belga Rossette Menegain, la francesa Liliane Burnier, y la espaâ”œâ–’ola Silvia Veiga. En el posado van vestidas a la manera tradicionalista de maja espaâ”œâ–’ola, y Jeannette luce capote de brega firmado para la ocasiâ”œâ”‚n por el popular matador de toros Manuel Benâ”œÂ¡tez "El Cordobâ”œÂ®s". El jurado del certamen estuvo compuesto por ilustres damas locales, esposas de las autoridades provinciales, y varios "crâ”œÂ¡ticos de bellezas femeninas" como el modisto Pedro Rodrâ”œÂ¡guez, el director del No-Do, Manuel Augusto Garcâ”œÂ¡a Viâ”œâ–’olas (se rodâ”œâ”‚ un reportaje para este noticiario), Pedro Chicote, y Antonio Mingote. Fuente visual: revista Blanco y Negro (Madrid), en hemeroteca.abc.es/', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65582800, -0.87662300, '0101000020E61000002D7C7DAD4B0DECBF8AE6012CF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34333147690.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34333147690.webp', 'https://www.flickr.com/photos/zaragozaantigua/34333147690/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24081, 'Calle Don Jaime 1904', 'Foto: Lete. En el marco de las fiestas de octubre, se celebrâ”œâ”‚ una recepciâ”œâ”‚n municipal a "los representantes de la Coronilla de Aragâ”œâ”‚n". La imagen capta el momento en que estos llegan "con su famosa senyera" hasta las casas del Ayuntamiento, al fondo. A la izquierda, fachada este de la Lonja. Fuente: Diario ABC, 27-10-1904.', 1904, 1904, 1904, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65574000, -0.87634200, '0101000020E6100000368FC360FE0AECBFEB56CF49EFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39256330224.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39256330224.webp', 'https://www.flickr.com/photos/zaragozaantigua/39256330224/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21354, 'Plaza de la Constituciâ”œâ”‚n 1900', 'Invernal escena capturada en la plaza de la Constituciâ”œâ”‚n centrada en el emboque a la calle de los Mâ”œÃ­rtires, flanqueada por los inmuebles de los nâ”œâ•‘meros 35-39 del Coso a la izquierda y los nâ”œâ•‘meros 41-45 a la derecha. En la solana de los bajos de estos edificios destaca la nutrida presencia de varias decenas de paisanos en lo que era denominado castiza y clasistamente "brasero de los pobres", uno de los varios existentes en la ciudad. A la derecha y en la calzada inmediata puede verse un coche cerrado tipo C, posiblemente de los construidos en Liverpool por Julius G. Neville, en servicio en la lâ”œÂ¡nea de Torrero. Si bien el Ayuntamiento habâ”œÂ¡a autorizado en 1898 el cambio de sistema de tracciâ”œâ”‚n para seguir asâ”œÂ¡ el modelo de la pionera Bilbao, en la imagen este coche sigue estando traccionado por una pareja de machos que le daban una velocidad media de 10-15 km/hora. En primer tâ”œÂ®rmino, la Fuente de la Princesa, sobre la que ya desde 1886 pendâ”œÂ¡a la amenaza de desmonte y sustituciâ”œâ”‚n primero por otra fuente "mâ”œÃ­s câ”œâ”‚moda y mâ”œÃ­s artâ”œÂ¡stica", una estatua del Justicia Juan Lanuza luego, y finalmente el monumento que hoy ocupa su lugar. Por ello, no eran extraâ”œâ–’os los abundantes y denigrantes epâ”œÂ¡tetos difundidos en la prensa de la â”œÂ®poca y dedicados a ella como cada vez que en esta ciudad se quiere derribar o desmontar algâ”œâ•‘n edificio o monumento: "antigua", "antiestâ”œÂ®tica", "horrible", "vetusta"... En la imagen puede apreciarse que le falta el brazo derecho, efecto derivado de la agresiâ”œâ”‚n de un paisano pasado de algo. Parece ser magnâ”œÂ®tica la presencia de este bulto redondo, se encuentre ubicado donde sea, a las agresiones en su contra, bien centradas en su extendido brazo derecho o bien en el tridente que porta. Ya en 1860 se le tuvo que reponer este mismo brazo con motivo de la visita de la reina Isabel II que tuvo lugar ese aâ”œâ–’o.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.65220100, -0.88104400, '0101000020E6100000E7C8CA2F8331ECBF91B586527BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54776029575.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54776029575.webp', 'https://www.flickr.com/photos/zaragozaantigua/54776029575/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24124, 'La Lonja 1966', 'Imagen capturada en la Lonja durante la "presentaciâ”œâ”‚n en sociedad" de treinta y cinco "damitas zaragozanas" pertenecientes a la alta sociedad local en la "Gran Gala de Debutantes" organizada por la Comisiâ”œâ”‚n de Fiestas el 8 de octubre de ese aâ”œâ–’o. La fiesta escenificâ”œâ”‚ que estas jâ”œâ”‚venes de la Zaragoza de bien vestâ”œÂ¡an "sus primeras galas de mujer" por primera vez en un festejo colectivo que tradicionalmente se realizaba de forma individual, bien en el Casino Mercantil, bien en la propia Lonja municipal. El inusual nâ”œâ•‘mero de "jovencitas" participantes en 1966 fue sustancialmente reducido en aâ”œâ–’os siguientes, probablemente para conferir al acto un carâ”œÃ­cter mâ”œÃ­s exclusivo y menos colectivo, o tal vez por el creciente desapego social a este tipo de ceremoniales tan carpetovetâ”œâ”‚nicos. En la imagen posan escalonadas las treinta y cinco "bellâ”œÂ¡simas seâ”œâ–’oritas debutantes en primorosos modelos de noche" portando una rosa roja. Las flanquean elementos de la Policâ”œÂ¡a Municipal en traje de gala. A la izquierda y ante el micrâ”œâ”‚fono, Demetrio Galâ”œÃ­n Bergua pronuncia un discurso "dedicado a exaltar las virtudes y belleza de nuestras mujeres" y donde les advertâ”œÂ¡a que "de ahora en adelante debâ”œÂ¡an ser modelos y prototipos de damas aragonesas", sea lo que sea que significara esta aserciâ”œâ”‚n.', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65581500, -0.87657800, '0101000020E61000002D944C4EED0CECBFF59CF4BEF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54664598920.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54664598920.webp', 'https://www.flickr.com/photos/zaragozaantigua/54664598920/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24125, 'La Lonja 1967', 'Imagen capturada en la Lonja durante la exclusiva e iniciâ”œÃ­tica "gran gala de debutantes" que tuvo lugar el 7 de octubre de ese aâ”œâ–’o organizada por el Ayuntamiento en beneficio de la Asociaciâ”œâ”‚n Nacional de la Lucha Contra el Câ”œÃ­ncer. La habitual presencia de las primeras autoridades locales fue eclipsada por acudir a ella para presidir el acto en carne mortal la unigâ”œÂ®nita Marâ”œÂ¡a del Carmen Franco Martâ”œÂ¡nez-Bordiâ”œâ•‘, consorte X marquesa de Villaverde, en su calidad de presidenta de la referida asociaciâ”œâ”‚n anticancerâ”œÂ¡gena, acompaâ”œâ–’ada por su esposo el docto marquâ”œÂ®s, al que las malas lenguas calificaban por razones que no vienen al cuento como "El Yernâ”œÂ¡simo", "marquâ”œÂ®s de Vespaverde" o "marquâ”œÂ®s de Vayavida". En esta ocasiâ”œâ”‚n fueron quince las "seâ”œâ–’oritas debutantes vestidas de blanco y magnâ”œÂ¡ficas en su juventud y belleza" que "vistieron sus primeras galas de mujer". En la imagen algunas de ellas posan ordenadas en filas tras saludar personalmente y recibir de manos de la marquesa de Villaverde sus "carnets de baile" y antes de su desfile tras el que se sentarâ”œÂ¡an para dar inicio a la cena y el posterior baile que durâ”œâ”‚ hasta las primeras horas de la madrugada, amenizado por las orquestas "Los Magos y Farrâ”œÂ®s" y el conjunto "Los Sarakostas" y que contâ”œâ”‚ ademâ”œÃ­s con las actuaciones de Marâ”œÂ¡a Dolores Pradera, acompaâ”œâ–’ada de los Gemelos; el dâ”œâ•‘o Juan y Junior, y el Quinteto del Club de Jazz de Radio Zaragoza.', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65581500, -0.87657800, '0101000020E61000002D944C4EED0CECBFF59CF4BEF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54668742814.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54668742814.webp', 'https://www.flickr.com/photos/zaragozaantigua/54668742814/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24138, 'Feria de Muestras 1934', 'Foto A. de la Barrera, 1934. Interior de la Lonja de Zaragoza durante la celebraciâ”œâ”‚n de la I Feria de Muestras Regional Aragonesa. Vemos la esquina suroeste del edificio, con el stand de la Sociedad General de Esterilizaciâ”œâ”‚n, cuyo domicilio social estaba en la calle de Joaquâ”œÂ¡n Costa 16. El procedimiento domâ”œÂ®stico Foncal, patentado por esa empresa, conseguâ”œÂ¡a matar las bacterias del agua mediante un proceso catalâ”œÂ¡tico, al instalar en las tuberâ”œÂ¡as un ingenio metâ”œÃ­lico. Fuente: Revista Aragâ”œâ”‚n, diciembre de 1934.', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65585400, -0.87681500, '0101000020E61000003B8DB454DE0EECBFB3791C06F3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20031364553.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20031364553.webp', 'https://www.flickr.com/photos/zaragozaantigua/20031364553/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24143, 'Feria de Muestras 1934', 'Plano del recinto de la I Feria de Muestras Regional Aragonesa, 1934. La Sociedad Econâ”œâ”‚mica Aragonesa de Amigos del Paâ”œÂ¡s organizâ”œâ”‚ en 1934 la primera Feria de Muestras Aragonesa en el palacio de la Lonja y sus jardines adyacentes. Se trataba de un muestrario de empresas de industria y comercio, que aparecen en el listado bajo el grâ”œÃ­fico. La entrada tenâ”œÂ¡a lugar en el edificio, por la calle Don Jaime I, y la salida por los jardines. Al aâ”œâ–’o siguiente se celebrâ”œâ”‚ la segunda, en la â”œâ•‘ltima zona de cubrimiento del râ”œÂ¡o Huerva, cercana a la plaza de Paraâ”œÂ¡so. No hubo mâ”œÃ­s, hasta 1941. Fuente: Revista Aragâ”œâ”‚n, diciembre de 1934.', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65592600, -0.87654600, '0101000020E610000056116E32AA0CECBF4D4C1762F5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20465197289.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20465197289.webp', 'https://www.flickr.com/photos/zaragozaantigua/20465197289/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24154, 'Expo 1919', 'Medalla en bronce realizada por el escultor Josâ”œÂ® Clara para conmemorar la Exposiciâ”œâ”‚n Hispano-Francesa de Bellas Artes celebrada en la Lonja durante los meses de mayo y junio de ese aâ”œâ–’o, en cuya secciâ”œâ”‚n espaâ”œâ–’ola se pudo ver obras de, entre otros, Nonell, Picasso, Regoyos, Zuloaga, Benlliure, Gargallo, Julio Antonio, y Macho. De la parte francesa, la representaciâ”œâ”‚n incluyâ”œâ”‚, entre otros, a los pintores Vlaminck, Friesz, Camoin, siendo la primera vez que en Zaragoza se veâ”œÂ¡an sus obras "fauves". Esta exposiciâ”œâ”‚n, a diferencia de la de 1908, apenas fue cubierta por los medios de comunicaciâ”œâ”‚n, de forma que casi nadie se enterâ”œâ”‚, ni antes, durante, ni despuâ”œÂ®s. La medalla de la imagen representa idealmente a Francia, con Marianne, y a Espaâ”œâ–’a, con una baturra, tal vez de nombre Pilar. Fuente visual: www.museunacional.cat/', 1919, 1919, 1919, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65580900, -0.87663000, '0101000020E6100000CC28965B5A0DECBF13B69F8CF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30144516644.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30144516644.webp', 'https://www.flickr.com/photos/zaragozaantigua/30144516644/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22315, 'Calle de Pedro Cubero c.1965', 'Procesiâ”œâ”‚n de Santa Rosa de Lima, patrona del barrio de Las Fuentes, a cargo de los tranviarios residentes en el Grupo Vizconde de Escoriaza, pasando por la calle de Pedro Cubero en direcciâ”œâ”‚n a la de Salvador Minguijâ”œâ”‚n, procedente la parroquia del mencionado Grupo de viviendas, levantado en 1953 para los trabajadores de la sociedad Tranvâ”œÂ¡as de Zaragoza. Su presidente, â”œÃ¼ngel Escoriaza Castillâ”œâ”‚n, introdujo el culto a la santa peruana en el barrio.', 1965, 1965, 1965, 'Anos 60', 'LAS FUENTES', 41.64783000, -0.86011000, '0101000020E61000004BCD1E680586EBBF10AFEB17ECD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15759816212.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15759816212.webp', 'https://www.flickr.com/photos/zaragozaantigua/15759816212/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24155, 'La Lonja 1919', 'Imagen del interior de la antigua Lonja, como escenario de la Exposiciâ”œâ”‚n Hispano-Francesa de Bellas Artes celebrada durante los meses de mayo y junio de ese aâ”œâ–’o. La toma longitudinal (posiblemente con el lienzo este al fondo), ilustra la disposiciâ”œâ”‚n espacial de algunos de los bultos redondos y cuadros de la exposiciâ”œâ”‚n, la decoraciâ”œâ”‚n con motivos florales, y la iluminaciâ”œâ”‚n por medio de grandes lâ”œÃ­mparas que penden de las renacentistas bâ”œâ”‚vedas. De entre los bultos redondos que aparecen en la imagen, destacamos las dos obras de Josâ”œÂ® Clarâ”œÃ­: "El crepâ”œâ•‘sculo", y "La diosa". Del local escultor Josâ”œÂ® Bueno, que entonces estaba terminando su recreaciâ”œâ”‚n del rey Alfonso I "El Batallador" para el monumento del cabezo de Buenavista, esta muestra contâ”œâ”‚ con sus obras "La tarde", y "Humanidad". La primera decorarâ”œÂ¡a un jardâ”œÂ¡n urbano cerca de la plaza de Aragâ”œâ”‚n, y la segunda serâ”œÂ¡a colocada en la "fosa comâ”œâ•‘n" del cementerio. Fuente visual: Foto Cepero, revista "La Esfera", en hemerotecadigital.bne.es/', 1919, 1919, 1919, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65580900, -0.87663000, '0101000020E6100000CC28965B5A0DECBF13B69F8CF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30752746936.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30752746936.webp', 'https://www.flickr.com/photos/zaragozaantigua/30752746936/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24163, 'Feria de Muestras 1934', 'Imagen con uno de los carteles anunciadores de la primera Feria de Muestras organizada en octubre de 1934 en el recinto de la Lonja y sus adyacentes jardines, en una instalaciâ”œâ”‚n coordinada por el arquitecto Borobio. El cartel, diseâ”œâ–’ado por Guillermo Pâ”œÂ®rez, recoge precisamente la antigua Lonja como escenario central de la muestra, y se centra en su fachada recayente a la calle de Don Jaime I. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65582800, -0.87662300, '0101000020E61000002D7C7DAD4B0DECBF8AE6012CF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36522148345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36522148345.webp', 'https://www.flickr.com/photos/zaragozaantigua/36522148345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24165, 'Paseo del Ebro 1934', 'Excepcional imagen capturada en el paseo del Ebro y centrada en el cruce con la calle de Don Jaime I, donde destaca el montaje realizado con motivo de la I Feria de Muestras Regional Aragonesa, celebrada entre el 5 y el 20 de octubre de 1934 en el espacio de la antigua Lonja, con 51 "stands", y los jardines inmediatos, donde se dio cabida a otros 27 "stands" ademâ”œÃ­s de un bar y un tablado para mâ”œâ•‘sica. Junto a la zona de los pabellones montados donde estuviera la antigua Casa Consistorial, delimitados por numerosas banderas y banderolas festivas, la caseta de consumos de la Puerta del â”œÃ¼ngel y el quiosco de la Sociedad Protectora de Animales. De fondo, la monumental fachada al paseo formada por las traseras de la calle del Pilar, con la Posada del Rey y el palacio de los marqueses de Ayerbe, y el templo del Pilar. Por el paseo circula un tranvâ”œÂ¡a de la lâ”œÂ¡nea "6. Magdalena-Mercado". En primer tâ”œÂ®rmino y a la izquierda, esquina del Seminario conciliar. Hacia la derecha, acceso al Puente de Piedra.', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65605600, -0.87621300, '0101000020E6100000C18F6AD8EF09ECBF1B2C9CA4F9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52278034883.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52278034883.webp', 'https://www.flickr.com/photos/zaragozaantigua/52278034883/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24219, 'Comparsa 1901', 'Gigantes y Cabezudos junto a la Lonja en 1901. La comparsa estâ”œÃ­ viniendo por la calle del Pilar (a la izquierda) hacia la de Don Jaime I. La imagen estâ”œÃ­ tomada desde la plaza de La Seo. En primer tâ”œÂ®rmino, el cabezudo Robaculeros.', 1901, 1901, 1901, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65546700, -0.87647600, '0101000020E61000001E537765170CECBFBA4DB857E6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15246931012.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15246931012.webp', 'https://www.flickr.com/photos/zaragozaantigua/15246931012/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24226, 'Timbaleros 1891', '"Los timbaleros de la ciudad de Zaragoza", â”œâ”‚leo sobre lienzo, Anselmo Gascâ”œâ”‚n de Gotor, 1891. Los timbaleros, al frente de una comitiva de ministriles seguida de los maceros. Tras ellos, los oficios concejiles con sombreros de copa. Salen del Ayuntamiento, a la derecha de la Lonja y fuera de la imagen. Al fondo, la calle del Pilar. Fuente: "El municipio en Aragâ”œâ”‚n", DPZ, 2004.', 1891, 1891, 1891, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65553200, -0.87653900, '0101000020E6100000B66455849B0CECBFA1BDFA78E8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20532962772.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20532962772.webp', 'https://www.flickr.com/photos/zaragozaantigua/20532962772/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
