INSERT INTO public.photos VALUES (24385, 'Calle del Pilar 1931', 'En el contexto de la celebraciâ”œâ”‚n del Centenario IV del nacimiento de Teresa de Cepeda y Ahumada, la Compaâ”œâ–’â”œÂ¡a de Santa Teresa de Jesâ”œâ•‘s proyecta en 1915 una expansiâ”œâ”‚n que incluye la estratâ”œÂ®gica plaza de Zaragoza, con la idea de fundar una escuela de formaciâ”œâ”‚n de maestras catâ”œâ”‚licas. En setiembre de ese aâ”œâ–’o llegan a la ciudad las primeras HH. Teresianas a buscar ubicaciâ”œâ”‚n, mientras se alojan donde las Oblatas (Pâ”¬â•‘ de las Damas). El Arzobispo Soldevila les ofrece las ruinas del antiguo convento de las Adoratrices, en San Juan de los Panetes, mas se inclinan por un piso de alquiler en la calle del Pilar, con el azulejo nâ”œâ•‘mero 19, en el edificio esquinero justo antes de la Seo, donde confluye la calle de Bayeu. Establecidas ya al comienzo de ese curso, el piso quedâ”œâ”‚ pronto pequeâ”œâ–’o, debiendo expandirse al entresuelo y a dos pisos extra del mismo edificio para dar cabida tanto a las alumnas internas de magisterio, como al alumnado externo de primeras enseâ”œâ–’anzas. La demanda de plazas continuaba, y resultaba imposible continuar allâ”œÂ¡, de forma que a comienzos de los aâ”œâ–’os 20 se buscâ”œâ”‚ una nueva ubicaciâ”œâ”‚n, mâ”œÃ­s espaciosa, que se encontrâ”œâ”‚ en los promisorios terrenos en urbanizaciâ”œâ”‚n de la antigua huerta de Santa Engracia, en el entorno de la nueva plaza de Castelar. La imagen de Roisin estâ”œÃ­ realizada desde la plaza de la Seo, cuando el Colegio Teresiano estaba ya en su nueva ubicaciâ”œâ”‚n de la calle Sanclemente, aunque la fenomenal fotografâ”œÂ¡a recoge tal vez la mejor instantâ”œÃ­nea con detalle del edificio de la calle del Pilar (donde la panaderâ”œÂ¡a) que acogiâ”œâ”‚ la primera sede zaragozana del Colegio Teresiano del Pilar. Como todos sus vecinos de zona, a excepciâ”œâ”‚n de la Lonja, este edificio serâ”œÂ¡a demolido a finales de dâ”œÂ®cada. Fuente visual: Lucien Roisin, "Lonja y torres del Pilar", en "Zaragoza, aâ”œâ–’os veinte. 81 fotografâ”œÂ¡as de Roisin (1925-1931)", Instituciâ”œâ”‚n Fernando el Catâ”œâ”‚lico, 2014. Fuente textual: Exposiciâ”œâ”‚n "Centenario Compaâ”œâ–’â”œÂ¡a Santa Teresa de Jesâ”œâ•‘s - Zaragoza", y la muy amable colaboraci', 1931, 1931, 1931, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65574200, -0.87692200, '0101000020E6100000BC92E4B9BE0FECBF8B4E965AEFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23134325411.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23134325411.webp', 'https://www.flickr.com/photos/zaragozaantigua/23134325411/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
